     1	import { useAuth, useModelIndex } from '@rhino-dev/rhino-react';
     2	import { NavLink, useLocation } from 'react-router-dom';
     3	import type { ReactNode } from 'react';
     4	import { Icon } from './Icons';
     5	import { initials } from '../lib/format';
     6	import type { Blog } from '../types';
     7	
     8	export function AppShell({ children }: { children: ReactNode }) {
     9	  const { logout } = useAuth();
    10	  const orgSlug = (typeof localStorage !== 'undefined' && localStorage.getItem('rhino_organization_slug')) || '';
    11	
    12	  const blogs = useModelIndex<Blog>('blogs', { perPage: 100 });
    13	  const blogsCount = blogs.data?.data?.length || null;
    14	
    15	  return (
    16	    <div className="shell">
    17	      <aside className="shell-sidebar">
    18	        <div className="brand">
    19	          <div className="brand-mark">R</div>
    20	          <div className="brand-name">Blog App <span>/web</span></div>
    21	        </div>
    22	        <nav className="nav">
    23	          <div className="nav-section">Workspace</div>
    24	          <Item to="/dashboard" icon={<Icon.layout />}>Dashboard</Item>
    25	          <Item to="/blogs"     icon={<Icon.edit />} badge={blogsCount}>Blogs</Item>
    26	
    27	          <div className="nav-section" style={{ marginTop: 10 }}>Admin</div>
    28	          <Item to="/members" icon={<Icon.users />}>Members</Item>
    29	          <Item to="/trash"   icon={<Icon.trash />}>Trash</Item>
    30	        </nav>
    31	        <div style={{ padding: 14, borderTop: '1px solid var(--border)', fontSize: 11, color: 'var(--fg-faint)' }}>
    32	          Powered by <span className="accent mono">@rhino-dev/rhino-react</span>
    33	        </div>
    34	      </aside>
    35	
    36	      <header className="shell-header">
    37	        <Breadcrumb />
    38	        <div className="header-actions">
    39	          {orgSlug && <span className="header-org-slug">/{orgSlug}</span>}
    40	          <UserChip />
    41	          <button className="btn btn-ghost btn-sm" onClick={() => logout()} title="Sign out">
    42	            <Icon.logout size={14} /> Sign out
    43	          </button>
    44	        </div>
    45	      </header>
    46	
    47	      <main className="shell-main">{children}</main>
    48	    </div>
    49	  );
    50	}
    51	
    52	function Item({ to, icon, badge, children }: { to: string; icon: ReactNode; badge?: number | null; children: ReactNode }) {
    53	  return (
    54	    <NavLink to={to} className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}>
    55	      <span className="icon">{icon}</span>
    56	      <span>{children}</span>
    57	      {badge != null && badge > 0 && <span className="badge">{badge}</span>}
    58	    </NavLink>
    59	  );
    60	}
    61	
    62	function Breadcrumb() {
    63	  const loc = useLocation();
    64	  const parts = loc.pathname.split('/').filter(Boolean);
    65	  if (parts.length === 0) return <span className="muted">Dashboard</span>;
    66	  return (
    67	    <div className="row faint">
    68	      {parts.map((p, i) => (
    69	        <span key={i}>
    70	          {i > 0 && <span style={{ margin: '0 6px' }}>/</span>}
    71	          <span style={{ color: i === parts.length - 1 ? 'var(--fg)' : undefined, textTransform: 'capitalize' }}>{p}</span>
    72	        </span>
    73	      ))}
    74	    </div>
    75	  );
    76	}
    77	
    78	function UserChip() {
    79	  // The current-user name is exposed by the LoginPage stashing it in localStorage.
    80	  const name  = typeof localStorage !== 'undefined' ? localStorage.getItem('rhino_user_name')  ?? 'User' : 'User';
    81	  const email = typeof localStorage !== 'undefined' ? localStorage.getItem('rhino_user_email') ?? '' : '';
    82	  return (
    83	    <div className="user-chip" title={email}>
    84	      <span className="avatar">{initials(name)}</span>
    85	      <span>{name}</span>
    86	    </div>
    87	  );
    88	}
